// Comprehensive data profiling for ETL preparation
const dataSources = inputs.data_sources || [];
const profilingResults = {};

for (const source of dataSources) {
  try {
    // Connect to source and analyze data quality
    const query = `
      SELECT 
        COUNT(*) as total_records,
        COUNT(DISTINCT ${source.primary_key}) as unique_records,
        MIN(${source.date_column}) as earliest_date,
        MAX(${source.date_column}) as latest_date,
        COUNT(CASE WHEN ${source.date_column} >= CURRENT_DATE - INTERVAL '1 DAY' THEN 1 END) as new_records_today
      FROM ${source.schema}.${source.table}
    `;

    const basicStats = await executeQuery(source.connection, query);

    // Detailed column profiling
    const columnProfiles = {};
    for (const column of source.columns || []) {
      const columnQuery = `
        SELECT 
          COUNT(*) as total_count,
          COUNT(${column}) as non_null_count,
          COUNT(DISTINCT ${column}) as unique_count,
          ${column === source.primary_key ? 'COUNT(CASE WHEN ' + column + ' IS NULL THEN 1 END)' : '0'} as null_key_count
        FROM ${source.schema}.${source.table}
      `;

      const columnStats = await executeQuery(source.connection, columnQuery);
      columnProfiles[column] = {
        ...columnStats[0],
        completeness_rate: (columnStats[0].non_null_count / columnStats[0].total_count * 100).toFixed(2),
        uniqueness_rate: (columnStats[0].unique_count / columnStats[0].total_count * 100).toFixed(2)
      };
    }

    // Data freshness analysis
    const freshnessQuery = `
      SELECT 
        DATE(${source.date_column}) as data_date,
        COUNT(*) as record_count
      FROM ${source.schema}.${source.table}
      WHERE ${source.date_column} >= CURRENT_DATE - INTERVAL '7 DAYS'
      GROUP BY DATE(${source.date_column})
      ORDER BY data_date DESC
    `;

    const freshnessData = await executeQuery(source.connection, freshnessQuery);

    profilingResults[source.name] = {
      basic_statistics: basicStats[0],
      column_profiles: columnProfiles,
      data_freshness: freshnessData,
      quality_score: calculateQualityScore(basicStats[0], columnProfiles),
      profiling_timestamp: new Date().toISOString(),
      recommendations: generateRecommendations(basicStats[0], columnProfiles, freshnessData)
    };

  } catch (error) {
    profilingResults[source.name] = {
      error: error.message,
      profiling_timestamp: new Date().toISOString(),
      status: 'failed'
    };
  }
}

function calculateQualityScore(basicStats, columnProfiles) {
  let score = 100;

  // Penalize for low uniqueness in primary key
  if (basicStats.total_records !== basicStats.unique_records) {
    score -= 20;
  }

  // Penalize for low completeness rates
  const avgCompleteness = Object.values(columnProfiles)
    .reduce((sum, col) => sum + parseFloat(col.completeness_rate), 0) / Object.keys(columnProfiles).length;

  if (avgCompleteness < 95) score -= (95 - avgCompleteness);

  // Penalize for data freshness issues
  if (basicStats.new_records_today === 0) score -= 10;

  return Math.max(0, Math.round(score));
}

function generateRecommendations(basicStats, columnProfiles, freshnessData) {
  const recommendations = [];

  if (basicStats.total_records !== basicStats.unique_records) {
    recommendations.push('Investigate primary key duplicates - may require deduplication logic');
  }

  for (const [column, profile] of Object.entries(columnProfiles)) {
    if (parseFloat(profile.completeness_rate) < 90) {
      recommendations.push(`Low completeness in ${column} (${profile.completeness_rate}%) - consider data imputation`);
    }
  }

  if (basicStats.new_records_today === 0) {
    recommendations.push('No new records today - verify data source is active');
  }

  return recommendations;
}

return { profiling_results: profilingResults };

// Dimension table processing with SCD Type 2 support
const dimensionConfig = inputs.dimension_config || {};
const profilingResults = inputs.profiling_results || {};
const dimensionResults = {};

for (const [dimName, config] of Object.entries(dimensionConfig)) {
  try {
    console.log(`Processing dimension: ${dimName}`);

    // Extract source data for dimension
    const sourceQuery = `
      SELECT DISTINCT
        ${config.business_key} as business_key,
        ${config.attributes.join(', ')},
        ${config.source_timestamp || 'CURRENT_TIMESTAMP'} as source_timestamp
      FROM ${config.source_schema}.${config.source_table}
      WHERE ${config.filter_condition || '1=1'}
        AND ${config.source_timestamp || 'created_at'} >= '${inputs.etl_start_date || '1900-01-01'}'
    `;

    const sourceData = await executeQuery(config.source_connection, sourceQuery);

    // Get existing dimension records
    const existingQuery = `
      SELECT 
        dimension_key,
        business_key,
        ${config.attributes.join(', ')},
        effective_date,
        expiration_date,
        is_current
      FROM ${config.target_schema}.${config.target_table}
      WHERE is_current = true
    `;

    const existingData = await executeQuery(config.target_connection, existingQuery);
    const existingMap = new Map(existingData.map(row => [row.business_key, row]));

    const dimensionChanges = {
      new_records: [],
      updated_records: [],
      unchanged_records: 0
    };

    // Process each source record
    for (const sourceRecord of sourceData) {
      const existingRecord = existingMap.get(sourceRecord.business_key);

      if (!existingRecord) {
        // New dimension record
        dimensionChanges.new_records.push({
          business_key: sourceRecord.business_key,
          ...config.attributes.reduce((obj, attr) => {
            obj[attr] = sourceRecord[attr];
            return obj;
          }, {}),
          effective_date: new Date().toISOString(),
          expiration_date: '9999-12-31T23:59:59Z',
          is_current: true,
          created_date: new Date().toISOString(),
          updated_date: new Date().toISOString()
        });
      } else {
        // Check if attributes have changed (SCD Type 2)
        const attributesChanged = config.attributes.some(attr => 
          sourceRecord[attr] !== existingRecord[attr]
        );

        if (attributesChanged) {
          // Close existing record
          dimensionChanges.updated_records.push({
            action: 'close_existing',
            dimension_key: existingRecord.dimension_key,
            expiration_date: new Date().toISOString(),
            is_current: false
          });

          // Create new current record
          dimensionChanges.new_records.push({
            business_key: sourceRecord.business_key,
            ...config.attributes.reduce((obj, attr) => {
              obj[attr] = sourceRecord[attr];
              return obj;
            }, {}),
            effective_date: new Date().toISOString(),
            expiration_date: '9999-12-31T23:59:59Z',
            is_current: true,
            created_date: new Date().toISOString(),
            updated_date: new Date().toISOString()
          });
        } else {
          dimensionChanges.unchanged_records++;
        }
      }
    }

    // Execute dimension updates
    if (dimensionChanges.updated_records.length > 0) {
      for (const update of dimensionChanges.updated_records) {
        if (update.action === 'close_existing') {
          const updateQuery = `
            UPDATE ${config.target_schema}.${config.target_table}
            SET expiration_date = '${update.expiration_date}',
                is_current = false,
                updated_date = CURRENT_TIMESTAMP
            WHERE dimension_key = '${update.dimension_key}'
          `;
          await executeQuery(config.target_connection, updateQuery);
        }
      }
    }

    // Insert new dimension records
    if (dimensionChanges.new_records.length > 0) {
      const insertQuery = `
        INSERT INTO ${config.target_schema}.${config.target_table}
        (business_key, ${config.attributes.join(', ')}, effective_date, expiration_date, is_current, created_date, updated_date)
        VALUES ${dimensionChanges.new_records.map(record => 
          `('${record.business_key}', ${config.attributes.map(attr => `'${record[attr]}'`).join(', ')}, '${record.effective_date}', '${record.expiration_date}', ${record.is_current}, '${record.created_date}', '${record.updated_date}')`
        ).join(', ')}
      `;

      await executeQuery(config.target_connection, insertQuery);
    }

    dimensionResults[dimName] = {
      source_records_processed: sourceData.length,
      new_records_created: dimensionChanges.new_records.length,
      existing_records_updated: dimensionChanges.updated_records.length,
      unchanged_records: dimensionChanges.unchanged_records,
      processing_timestamp: new Date().toISOString(),
      status: 'completed'
    };

  } catch (error) {
    dimensionResults[dimName] = {
      error: error.message,
      processing_timestamp: new Date().toISOString(),
      status: 'failed'
    };
  }
}

return { dimension_results: dimensionResults };

// Fact table processing with dimension key lookups
const factConfig = inputs.fact_config || {};
const dimensionResults = inputs.dimension_results || {};
const factResults = {};

for (const [factName, config] of Object.entries(factConfig)) {
  try {
    console.log(`Processing fact table: ${factName}`);

    // Build dimension lookup queries
    const dimensionLookups = {};
    for (const dimLookup of config.dimension_lookups || []) {
      const lookupQuery = `
        SELECT business_key, dimension_key
        FROM ${dimLookup.schema}.${dimLookup.table}
        WHERE is_current = true
      `;
      dimensionLookups[dimLookup.name] = await executeQuery(dimLookup.connection, lookupQuery);
    }

    // Create lookup maps for performance
    const lookupMaps = {};
    for (const [dimName, dimData] of Object.entries(dimensionLookups)) {
      lookupMaps[dimName] = new Map(dimData.map(row => [row.business_key, row.dimension_key]));
    }

    // Extract source fact data
    const sourceQuery = `
      SELECT 
        ${config.source_columns.join(', ')},
        ${config.measure_columns.join(', ')},
        ${config.date_column} as transaction_date
      FROM ${config.source_schema}.${config.source_table}
      WHERE ${config.date_column} >= '${inputs.etl_start_date || '1900-01-01'}'
        AND ${config.filter_condition || '1=1'}
      ORDER BY ${config.date_column}
    `;

    const sourceData = await executeQuery(config.source_connection, sourceQuery);

    // Process fact records with dimension key lookups
    const processedFacts = [];
    const orphanedRecords = [];

    for (const sourceRecord of sourceData) {
      const factRecord = {
        ...sourceRecord,
        etl_batch_id: inputs.batch_id || new Date().toISOString(),
        created_date: new Date().toISOString()
      };

      let allDimensionsFound = true;

      // Resolve dimension keys
      for (const dimLookup of config.dimension_lookups || []) {
        const businessKey = sourceRecord[dimLookup.business_key_column];
        const dimensionKey = lookupMaps[dimLookup.name].get(businessKey);

        if (dimensionKey) {
          factRecord[dimLookup.target_column] = dimensionKey;
        } else {
          // Handle missing dimension
          if (dimLookup.handle_missing === 'create_unknown') {
            // Create or get 'Unknown' dimension record
            factRecord[dimLookup.target_column] = await getOrCreateUnknownDimension(
              dimLookup.schema, 
              dimLookup.table, 
              dimLookup.connection
            );
          } else if (dimLookup.handle_missing === 'skip_record') {
            allDimensionsFound = false;
            orphanedRecords.push({
              ...sourceRecord,
              missing_dimension: dimLookup.name,
              missing_business_key: businessKey
            });
            break;
          } else {
            factRecord[dimLookup.target_column] = null;
          }
        }
      }

      if (allDimensionsFound) {
        processedFacts.push(factRecord);
      }
    }

    // Batch insert processed facts
    if (processedFacts.length > 0) {
      const batchSize = 1000;
      let insertedCount = 0;

      for (let i = 0; i < processedFacts.length; i += batchSize) {
        const batch = processedFacts.slice(i, i + batchSize);

        const insertColumns = [
          ...config.source_columns,
          ...config.measure_columns,
          ...config.dimension_lookups.map(d => d.target_column),
          'transaction_date',
          'etl_batch_id',
          'created_date'
        ];

        const insertValues = batch.map(record => 
          `(${insertColumns.map(col => {
            const value = record[col];
            return value === null || value === undefined ? 'NULL' : `'${value}'`;
          }).join(', ')})`
        ).join(', ');

        const insertQuery = `
          INSERT INTO ${config.target_schema}.${config.target_table}
          (${insertColumns.join(', ')})
          VALUES ${insertValues}
        `;

        await executeQuery(config.target_connection, insertQuery);
        insertedCount += batch.length;
      }
    }

    // Log orphaned records for investigation
    if (orphanedRecords.length > 0) {
      const orphanLogQuery = `
        INSERT INTO ${config.target_schema}.fact_orphan_log
        (fact_table, orphan_data, missing_dimension, processing_date)
        VALUES ${orphanedRecords.map(record => 
          `('${factName}', '${JSON.stringify(record)}', '${record.missing_dimension}', CURRENT_TIMESTAMP)`
        ).join(', ')}
      `;

      await executeQuery(config.target_connection, orphanLogQuery);
    }

    factResults[factName] = {
      source_records_processed: sourceData.length,
      fact_records_inserted: processedFacts.length,
      orphaned_records: orphanedRecords.length,
      processing_timestamp: new Date().toISOString(),
      status: 'completed'
    };

  } catch (error) {
    factResults[factName] = {
      error: error.message,
      processing_timestamp: new Date().toISOString(),
      status: 'failed'
    };
  }
}

async function getOrCreateUnknownDimension(schema, table, connection) {
  // Check if 'Unknown' record exists
  const checkQuery = `SELECT dimension_key FROM ${schema}.${table} WHERE business_key = 'UNKNOWN' AND is_current = true`;
  const existing = await executeQuery(connection, checkQuery);

  if (existing.length > 0) {
    return existing[0].dimension_key;
  } else {
    // Create 'Unknown' dimension record
    const insertQuery = `
      INSERT INTO ${schema}.${table}
      (business_key, name, effective_date, expiration_date, is_current, created_date)
      VALUES ('UNKNOWN', 'Unknown', CURRENT_TIMESTAMP, '9999-12-31', true, CURRENT_TIMESTAMP)
      RETURNING dimension_key
    `;

    const inserted = await executeQuery(connection, insertQuery);
    return inserted[0].dimension_key;
  }
}

return { fact_results: factResults };

// Post-ETL data quality validation
const qualityTests = inputs.quality_tests || {};
const validationResults = {};

for (const [testName, testConfig] of Object.entries(qualityTests)) {
  try {
    const testQuery = testConfig.query.replace(/\{([^}]+)\}/g, (match, param) => {
      return inputs[param] || match;
    });

    const testResult = await executeQuery(testConfig.connection, testQuery);
    const actualValue = testResult[0][testConfig.metric_column];

    const passed = evaluateTestCondition(
      actualValue, 
      testConfig.operator, 
      testConfig.expected_value
    );

    validationResults[testName] = {
      test_type: testConfig.test_type,
      actual_value: actualValue,
      expected_value: testConfig.expected_value,
      operator: testConfig.operator,
      passed: passed,
      severity: testConfig.severity || 'medium',
      execution_time: new Date().toISOString()
    };

  } catch (error) {
    validationResults[testName] = {
      error: error.message,
      passed: false,
      severity: 'high',
      execution_time: new Date().toISOString()
    };
  }
}

function evaluateTestCondition(actual, operator, expected) {
  switch (operator) {
    case 'equals': return actual == expected;
    case 'not_equals': return actual != expected;
    case 'greater_than': return parseFloat(actual) > parseFloat(expected);
    case 'less_than': return parseFloat(actual) < parseFloat(expected);
    case 'greater_equal': return parseFloat(actual) >= parseFloat(expected);
    case 'less_equal': return parseFloat(actual) <= parseFloat(expected);
    case 'between': 
      const [min, max] = expected.split(',').map(v => parseFloat(v.trim()));
      return parseFloat(actual) >= min && parseFloat(actual) <= max;
    default: return false;
  }
}

const overallScore = Object.values(validationResults)
  .filter(result => result.passed !== undefined)
  .reduce((sum, result) => sum + (result.passed ? 1 : 0), 0) / Object.keys(validationResults).length * 100;

const failedTests = Object.entries(validationResults)
  .filter(([_, result]) => result.passed === false)
  .map(([testName, result]) => ({ test: testName, ...result }));

return { 
  validation_results: validationResults, 
  overall_quality_score: Math.round(overallScore),
  failed_tests: failedTests,
  validation_summary: {
    total_tests: Object.keys(validationResults).length,
    passed_tests: Object.values(validationResults).filter(r => r.passed === true).length,
    failed_tests: failedTests.length,
    critical_failures: failedTests.filter(t => t.severity === 'high').length
  }
};

// ETL performance analysis and optimization
const performanceMetrics = {
  total_execution_time_ms: inputs.execution_time_ms || 0,
  dimension_processing_time: Object.values(inputs.dimension_results || {})
    .reduce((sum, dim) => sum + (dim.processing_time_ms || 0), 0),
  fact_processing_time: Object.values(inputs.fact_results || {})
    .reduce((sum, fact) => sum + (fact.processing_time_ms || 0), 0),
  total_records_processed: Object.values(inputs.fact_results || {})
    .reduce((sum, fact) => sum + (fact.source_records_processed || 0), 0),
  memory_usage_peak_mb: inputs.memory_usage_mb || 0,
  cpu_usage_avg_percent: inputs.cpu_usage_percent || 0
};

// Calculate throughput metrics
const executionTimeSeconds = performanceMetrics.total_execution_time_ms / 1000;
performanceMetrics.records_per_second = executionTimeSeconds > 0 
  ? (performanceMetrics.total_records_processed / executionTimeSeconds).toFixed(2)
  : 0;

// Generate optimization recommendations
const optimizations = [];

if (parseFloat(performanceMetrics.records_per_second) < 1000) {
  optimizations.push({
    type: 'throughput',
    recommendation: 'Consider increasing batch sizes or parallel processing',
    current_value: performanceMetrics.records_per_second + ' records/sec',
    target_value: '> 1000 records/sec'
  });
}

if (performanceMetrics.memory_usage_peak_mb > 2048) {
  optimizations.push({
    type: 'memory',
    recommendation: 'Reduce batch sizes or implement streaming processing',
    current_value: performanceMetrics.memory_usage_peak_mb + ' MB',
    target_value: '< 2048 MB'
  });
}

if (performanceMetrics.cpu_usage_avg_percent > 80) {
  optimizations.push({
    type: 'cpu',
    recommendation: 'Optimize SQL queries or distribute load across multiple workers',
    current_value: performanceMetrics.cpu_usage_avg_percent + '%',
    target_value: '< 80%'
  });
}

if (performanceMetrics.total_execution_time_ms > 3600000) { // > 1 hour
  optimizations.push({
    type: 'duration',
    recommendation: 'Consider incremental processing or partitioning strategies',
    current_value: (performanceMetrics.total_execution_time_ms / 60000).toFixed(1) + ' minutes',
    target_value: '< 60 minutes'
  });
}

// Historical performance comparison
const performanceHistory = inputs.historical_performance || [];
const improvementAnalysis = {};

if (performanceHistory.length > 0) {
  const lastRun = performanceHistory[performanceHistory.length - 1];
  improvementAnalysis.execution_time_change = 
    ((performanceMetrics.total_execution_time_ms - lastRun.total_execution_time_ms) / lastRun.total_execution_time_ms * 100).toFixed(2);
  improvementAnalysis.throughput_change = 
    ((parseFloat(performanceMetrics.records_per_second) - parseFloat(lastRun.records_per_second)) / parseFloat(lastRun.records_per_second) * 100).toFixed(2);
}

return {
  performance_metrics: performanceMetrics,
  optimization_recommendations: optimizations,
  improvement_analysis: improvementAnalysis,
  performance_rating: optimizations.length === 0 ? 'excellent' : 
                     optimizations.length <= 2 ? 'good' : 
                     optimizations.length <= 4 ? 'fair' : 'needs_improvement'
};
